+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { isRelation } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import type { Trait, TraitRecord, TraitValue } from '../trait/types';
+import type { World } from '../world';
+import type { Aspect, AspectInput, AspectValue } from './types';
+
+let aspectId = -1;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$internal]?.aspect;
+}
+
+export function createAspect<const T extends readonly AspectInput[]>(...inputs: T): Aspect<T> {
+    if (inputs.length < 2) throw new Error('Koota: An aspect requires at least two traits.');
+
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isRelation(input)) throw new Error('Koota: Relations cannot be aspect constituents.');
+        const members = isAspect(input) ? input.traits : [input as Trait];
+        for (const trait of members) {
+            if (trait[$internal].relation)
+                throw new Error('Koota: Relation traits cannot be aspect constituents.');
+            traits.push(trait);
+        }
+    }
+
+    const schema: Record<string, unknown> = {};
+    const owners = new Map<string, Trait>();
+    for (const trait of traits) {
+        const traitSchema = trait.schema;
+        if (typeof traitSchema === 'function') continue;
+        for (const key of Object.keys(traitSchema)) {
+            if (owners.has(key))
+                throw new Error(`Koota: Aspect constituents overlap on field "${key}".`);
+            owners.set(key, trait);
+            schema[key] = traitSchema[key];
+        }
+    }
+
+    const id = aspectId--;
+    const aspect = Object.assign((value?: AspectValue<Aspect<T>>) => [aspect, value], {
+        id,
+        traits: Object.freeze(traits.slice()),
+        schema: Object.freeze(schema),
+        [$internal]: { aspect: true as const, owners },
+    }) as Aspect<T>;
+    return aspect;
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(world: World, entity: Entity, aspect: Aspect): AspectValue<Aspect> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    const result: Record<string, unknown> = {};
+    for (const trait of aspect.traits) Object.assign(result, getTrait(world, entity, trait));
+    return result;
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: any, triggerChanged = true) {
+    if (value instanceof Function) value = value(getAspect(world, entity, aspect));
+    const values = splitAspectValue(aspect, value);
+    for (const [trait, traitValue] of values) setTrait(world, entity, trait, traitValue, triggerChanged);
+}
+
+export function addAspect(world: World, entity: Entity, aspect: Aspect, value?: any) {
+    const values = splitAspectValue(aspect, value);
+    for (const trait of aspect.traits) {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, values.get(trait)]);
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    removeTrait(world, entity, ...aspect.traits);
+}
+
+export function splitAspectValue(aspect: Aspect, value: any): Map<Trait, Record<string, unknown> | undefined> {
+    const values = new Map<Trait, Record<string, unknown> | undefined>();
+    for (const trait of aspect.traits) values.set(trait, undefined);
+    if (!value) return values;
+    for (const key of Object.keys(value)) {
+        const trait = aspect[$internal].owners.get(key);
+        if (!trait) continue;
+        let traitValue = values.get(trait);
+        if (!traitValue) values.set(trait, (traitValue = {}));
+        traitValue[key] = value[key];
+    }
+    return values;
+}
+
+export function getAspectRecord(aspect: Aspect, records: TraitRecord<any>[]): AspectValue<Aspect> {
+    const result: Record<string, unknown> = {};
+    for (const record of records) Object.assign(result, record);
+    return result;
+}
